// Define research keywords and competitor URLs
const researchConfig = {
  keywords: [
    "AI Marketing Trends 2025",
    "Marketing Automation Innovations",
    "Digital Transformation Case Studies"
  ],
  competitors: [
    "https://www.example-competitor1.com",
    "https://www.example-competitor2.com"
  ],
  industry: "Marketing Technology",
  region: "Global",
  timestamp: new Date().toISOString()
};

return [
  {
    json: researchConfig
  }
];

// Prepare prompt for AI analysis
const newsData = $input.all()[0].json;
const competitorData = $input.all()[1].json;

// Extract relevant text from news articles
const newsArticles = newsData.articles ? 
  newsData.articles.slice(0, 10).map(article => ({
    title: article.title,
    description: article.description,
    content: article.content ? article.content.substring(0, 500) : '',
    source: article.source?.name || 'Unknown',
    publishedAt: article.publishedAt
  })) : [];

// Generate analysis prompt
const analysisPrompt = `
Perform a market analysis for the "${newsData.industry || 'Marketing Technology'}" industry based on the following data.

## Collected News (Top 10)
${newsArticles.map((article, i) => 
  `### Article ${i+1}: ${article.title}\n` +
  `Source: ${article.source} | Date: ${article.publishedAt}\n` +
  `Summary: ${article.description || article.content}\n`
).join('\n')}

## Instructions
Please create a comprehensive market analysis report in Markdown format including:

### 1. SWOT Analysis
- Strengths, Weaknesses, Opportunities, and Threats (3 points each).

### 2. Market Trends
- Top 5 trends with their significance.

### 3. Competitor Movements
- Key observations from current players.

### 4. Action Plan
- 3 concrete actions for the next 30 days.

### 5. Executive Summary
- A concise summary under 300 characters.
`;

return [{
  json: {
    prompt: analysisPrompt,
    newsArticles: newsArticles,
    timestamp: new Date().toISOString(),
    industry: newsData.industry || 'Marketing Technology'
  }
}];

