// Structure the AI response for downstream nodes
const aiResponse = $input.first().json;
const analysisText = aiResponse.choices?.[0]?.message?.content || '';

if (!analysisText) {
  throw new Error('AI analysis result is empty. Check API response.');
}

const result = {
  fullReport: analysisText,
  timestamp: new Date().toISOString(),
  metadata: {
    model: aiResponse.model || 'gpt-4o',
    tokensUsed: aiResponse.usage?.total_tokens || 0
  },
  executiveSummary: analysisText.match(/### 5\. Executive Summary[\s\S]*?\n([^#]+)/)?.[1]?.trim() || 
                    analysisText.substring(0, 300) + '...',
  reportTitle: `Market Analysis Report - ${new Date().toLocaleDateString('en-US')}`,
  generatedAt: new Date().toLocaleString('en-US', { timeZone: 'UTC' })
};

return [{
  json: result
}];

